class Calculator {constructor(previousOperandTextElement,currentOperandTextElement) {this.previousOperandTextElement = previousOperandTextElement;this.currentOperandTextElement = currentOperandTextElement;this.history = [];this.clear();}clear() {this.currentOperand = '';this.previousOperand = '';this.operation = undefined;this.updateDisplay();}delete() {this.currentOperand = this.currentOperand.toString().slice(0,-1);if (this.currentOperand === '') {this.currentOperand = '0';}this.updateDisplay();}appendNumber(number) {if (number === '.' && this.currentOperand.includes('.')) return;if (this.currentOperand === '0' && number !== '.') {this.currentOperand = number.toString();}else {this.currentOperand = this.currentOperand.toString() + number.toString();}this.updateDisplay();}chooseOperation(operation) {if (this.currentOperand === '') return;if (this.previousOperand !== '') {this.compute();}this.operation = operation;this.previousOperand = this.currentOperand;this.currentOperand = '';this.updateDisplay();}compute() {let computation;const prev = parseFloat(this.previousOperand);const current = parseFloat(this.currentOperand);if (isNaN(prev) || isNaN(current)) return;const calculation = `${this.getDisplayNumber(this.previousOperand)}${this.operation}${this.getDisplayNumber(this.currentOperand)}`;switch (this.operation) {case '+':computation = prev + current;break;case '-':computation = prev - current;break;case '×':computation = prev * current;break;case '÷':if (current === 0) {alert('Cannot divide by zero!');return;}computation = prev / current;break;case '%':computation = (prev * current) / 100;break;default:return;}this.addToHistory(calculation,computation);this.currentOperand = computation;this.operation = undefined;this.previousOperand = '';this.updateDisplay();}getDisplayNumber(number) {const stringNumber = number.toString();const integerDigits = parseFloat(stringNumber.split('.')[0]);const decimalDigits = stringNumber.split('.')[1];let integerDisplay;if (isNaN(integerDigits)) {integerDisplay = '';}else {integerDisplay = integerDigits.toLocaleString('en',{maximumFractionDigits:0});}if (decimalDigits != null) {return `${integerDisplay}.${decimalDigits}`;}else {return integerDisplay;}}updateDisplay() {if (this.currentOperand === '') {this.currentOperandTextElement.innerText = '0';}else {this.currentOperandTextElement.innerText = this.getDisplayNumber(this.currentOperand);}if (this.operation != null) {this.previousOperandTextElement.innerText = `${this.getDisplayNumber(this.previousOperand)}${this.operation}`;}else {this.previousOperandTextElement.innerText = '';}}addToHistory(calculation,result) {const historyItem = {calculation:calculation,result:this.getDisplayNumber(result),time:new Date().toLocaleTimeString()};this.history.unshift(historyItem);if (this.history.length > 50) {this.history = this.history.slice(0,50);}this.updateHistoryDisplay();}updateHistoryDisplay() {const historyList = document.getElementById('historyList');if (this.history.length === 0) {historyList.innerHTML = '<div class="history-empty">No calculations yet</div>';return;}let historyHTML = '';this.history.forEach((item,index) => {historyHTML += ` <div class="history-item" onclick="calculator.loadFromHistory(${index})"> <div class="history-calculation">${item.calculation}</div> <div class="history-result">= ${item.result}</div> <div class="history-time">${item.time}</div> </div> `;});historyList.innerHTML = historyHTML;}loadFromHistory(index) {const item = this.history[index];this.currentOperand = item.result.replace(/,/g,'');this.previousOperand = '';this.operation = undefined;this.updateDisplay();}clearHistory() {this.history = [];this.updateHistoryDisplay();}}const previousOperandTextElement = document.getElementById('previousOperand');const currentOperandTextElement = document.getElementById('currentOperand');const calculator = new Calculator(previousOperandTextElement,currentOperandTextElement);document.addEventListener('keydown',function(event) {const key = event.key;if (key >= '0' && key <= '9') {calculator.appendNumber(key);}else if (key === '.') {calculator.appendNumber('.');}else if (key === '+') {calculator.chooseOperation('+');}else if (key === '-') {calculator.chooseOperation('-');}else if (key === '*') {calculator.chooseOperation('×');}else if (key === '/') {event.preventDefault();calculator.chooseOperation('÷');}else if (key === '%') {calculator.chooseOperation('%');}else if (key === 'Enter' || key === '=') {event.preventDefault();calculator.compute();}else if (key === 'Escape' || key === 'c' || key === 'C') {calculator.clear();}else if (key === 'Backspace') {calculator.delete();}});document.addEventListener('DOMContentLoaded',function() {const mobileMenuToggle = document.querySelector('.mobile-menu-toggle');const navMenu = document.querySelector('.nav-menu');if (mobileMenuToggle && navMenu) {mobileMenuToggle.addEventListener('click',function() {navMenu.style.display = navMenu.style.display === 'flex' ? 'none' :'flex';navMenu.style.position = 'absolute';navMenu.style.top = '100%';navMenu.style.left = '0';navMenu.style.right = '0';navMenu.style.background = 'white';navMenu.style.flexDirection = 'column';navMenu.style.padding = '1rem';navMenu.style.boxShadow = '0 5px 15px rgba(0,0,0,0.1)';navMenu.style.borderRadius = '0 0 10px 10px';});}document.querySelectorAll('a[href^="#"]').forEach(anchor => {anchor.addEventListener('click',function (e) {e.preventDefault();const target = document.querySelector(this.getAttribute('href'));if (target) {target.scrollIntoView({behavior:'smooth',block:'start'});}});});document.querySelectorAll('.category-list a').forEach(link => {link.addEventListener('click',function(e) {this.style.opacity = '0.7';this.innerHTML += ' <i class="fas fa-spinner fa-spin"></i>';setTimeout(() => {this.style.opacity = '1';const spinner = this.querySelector('.fa-spinner');if (spinner) {spinner.remove();}},1000);});});});document.addEventListener('DOMContentLoaded',function() {const observerOptions = {threshold:0.1,rootMargin:'0px 0px -50px 0px'};const observer = new IntersectionObserver(function(entries) {entries.forEach(entry => {if (entry.isIntersecting) {entry.target.style.opacity = '1';entry.target.style.transform = 'translateY(0)';}});},observerOptions);document.querySelectorAll('.category-card').forEach(card => {card.style.opacity = '0';card.style.transform = 'translateY(20px)';card.style.transition = 'opacity 0.6s ease,transform 0.6s ease';observer.observe(card);});});